			GM_log(i+1,secToSrtFormat(startTime),secToSrtFormat(endTime),subtitle);
			srt += i+1+ '\n' + secToSrtFormat(startTime) + ' --> '+ secToSrtFormat(endTime) + '\n' + subtitle + '\n\n';
