}
//
function handleSub(myString, id){
	//console.warn(blob);
	document.querySelector('#myFloat').innerHTML += '<textarea name="mbar'+ id + '" rows="4" cols="30">' + myString + '</textarea><br><button id="' + id + '" style="background-color: ' + colors[id] + '; padding:5px;">'+btnNames[id]+'</button><hr>';
	//place.innerHTML += '<li><button id="mySave" >Create file</button></li>';
	//place.querySelector('li:last-child button').onclick = function() {
	//  saveAs(blob, title+".srt")
	//}
	document.getElementById(id.toString()).addEventListener("click", function() {
		var blob = new Blob([myString], {type: "text/plain;charset=utf-8"});
		saveAs(blob, title+".srt");
	},true);
}
//
function secToSrtFormat(s){
	// s == second
	s = s.toFixed(3);
	var array = s.split('.');
	var Hour = 0;
	var Minute = 0;
	var Second = array[0];   // 671
	var MilliSecond = array[1];  // 330
	if(Second >= 60){
		Minute = Math.floor(Second / 60);
		Second = Second - Minute * 60;
		Hour = Math.floor(Minute / 60);
		Minute = Minute - Hour * 60;
	}
	if (Minute < 10){
		Minute = '0' + Minute;
	}
	// Hour
	if (Hour < 10){
		Hour = '0' + Hour;
	}
	// Second
	if (Second < 10){
		Second = '0' + Second;
	}
	return Hour + ':' + Minute + ':' + Second + ',' + MilliSecond;
}

