                while value:
                    try:
                        self.sub = await aioredis.create_redis((self.host, self.port),
                                                               db=self.db,
                                                               password=self.password)
                        value=False
                    except:
                        pass
                self.ch = (await self.sub.subscribe(self.channel))[0]
                return await self.ch.get()
